+      <div className="flex h-full flex-col gap-4">
+        <div className="flex items-start justify-between gap-3">
+          <div className="min-w-0">
+            <h3 className="line-clamp-2 font-semibold">{requestTitle(request)}</h3>
+            <p className="mt-1 text-sm text-muted-foreground">{request.productPath ?? "Contextaanvraag"}</p>
+          </div>
+          <Badge variant={request.id.startsWith("submitted") ? "secondary" : "outline"}>
+            {requestStatus(request)}
+          </Badge>
+        </div>
+
+        <div className="grid gap-2 text-sm text-muted-foreground">
+          <div className="flex items-center justify-between gap-2">
+            <span>Goedkeuring</span>
+            <span className="text-right font-medium text-foreground">{requestApprovalStatus(request)}</span>
+          </div>
+          <div className="flex items-center justify-between gap-2">
+            <span>Type</span>
+            <span className="text-right font-medium text-foreground">{request.shortLabel ?? request.label}</span>
+          </div>
+          <div className="flex items-center justify-between gap-2">
+            <span>Product</span>
+            <span className="text-right font-medium text-foreground">
+              {request.productLabel ?? "Niet-productgebonden"}
+            </span>
+          </div>
+        </div>
+
+        <Separator />
+
+        <div className="mt-auto flex flex-wrap items-center gap-2">
+          {request.value ? <Badge variant="outline">{request.value}</Badge> : null}
+          <span className="font-mono text-xs text-muted-foreground">{request.id}</span>
+        </div>
+      </div>
+    </Card>
+  );
+}
+
+function RequestsOverviewContent() {
+  const navigate = useNavigate();
+  const { openPanel } = useAppPanels();
+  const [requests] = useAuthenticatedRequests();
+
+  return (
+    <div className="flex h-full w-full flex-col gap-6 overflow-auto px-4 py-6">
+      <div className="flex flex-col gap-4 rounded-xl border border-border/70 bg-card p-5 shadow-proc-xs md:flex-row md:items-start md:justify-between">
+        <div className="max-w-2xl">
+          <Badge variant="secondary">Aangemelde omgeving</Badge>
+          <h1 className="mt-3 text-2xl font-semibold tracking-tight">Aanvragen</h1>
+          <p className="mt-2 text-sm leading-6 text-muted-foreground">
+            Concepten en ingestuurde aanvragen blijven zichtbaar in dit overzicht. Start een nieuwe aanvraag of open
+            een bestaande request voor detail en bewerking.
+          </p>
